const brandSubmenuRight=document.getElementById("brand-submenu-right"),brandSubmenuImages=document.getElementById("brand-submenu-images"),brandMenuContent=document.querySelector(".brand-menu-content > .left");function renderBrandMenu(){const subcategories=translations.brand.subcategories;for(let s of subcategories)s.link?brandMenuContent.innerHTML+=`<a href="${s.link}" target="_blank" class="menu-label brand"><span data-submenu="${s.key}" class="span">${s.title}</span></a>`:brandMenuContent.innerHTML+=`<div class="menu-label brand"><span data-submenu="${s.key}" class="span">${s.title}</span></div>`}function renderBrandSubMenu(key){brandSubmenuRight.style.opacity="1";const options=translations.brand.subcategories.find(e=>e.key===key).options;brandSubmenuRight.innerHTML="";for(let o of options)brandSubmenuRight.innerHTML+=`<a href="${o.link}" class="menu-label brand" style="text-transform:none">${o.title}</a>`}function renderBrandImages(key){brandSubmenuImages.innerHTML="";let images=[];images=null===key?translations.brand.defaultImages:translations.brand.subcategories.find(e=>e.key===key).images;for(let img of images)brandSubmenuImages.innerHTML+=`\n    <a class="brand-imgWrapper" href="${img.link}" target="_blank">\n      <img src="${img.src}" alt="${img.title}">\n      <div class="imgLabel">${img.title}</div>\n    </a>`}document.querySelectorAll(".menu-label.brand > .span[data-submenu]").forEach(label=>{label.addEventListener("click",()=>{const selected=label.dataset.submenu;document.querySelectorAll(".menu-label"),renderBrandSubMenu(selected),renderBrandImages(selected)})}),renderBrandImages(null);
